// NestJS Core
declare module '@nestjs/core' {
  export class NestFactory {
    static create(module: any): Promise<any>;
  }
  export class Reflector {
    constructor();
    get<T>(key: string, target: any): T;
    set(key: string, value: any, target: any): void;
    getAllAndOverride<T>(key: string, targets: any[]): T;
  }
}

declare module '@nestjs/common' {
  export function Injectable(): ClassDecorator;
  export function Controller(path?: string): ClassDecorator;
  export function Get(path?: string): MethodDecorator;
  export function Post(path?: string): MethodDecorator;
  export function Put(path?: string): MethodDecorator;
  export function Delete(path?: string): MethodDecorator;
  export function Patch(path?: string): MethodDecorator;
  export function Body(): ParameterDecorator;
  export function Query(): ParameterDecorator;
  export function Param(): ParameterDecorator;
  export function Req(): ParameterDecorator;
  export function Res(): ParameterDecorator;
  export function UseGuards(...guards: any[]): ClassDecorator;
  export function UseInterceptors(...interceptors: any[]): ClassDecorator;
  export function UseFilters(...filters: any[]): ClassDecorator;
  export function createParamDecorator(factory: Function): ParameterDecorator;
  export function SetMetadata(key: string, value: any): ClassDecorator;
  export class ValidationPipe {
    constructor(options?: any);
  }
  export class UnauthorizedException extends Error { }
  export class NotFoundException extends Error { }
  export class BadRequestException extends Error { }
  export class ConflictException extends Error { }
  export class ForbiddenException extends Error { }
  export class ServiceUnavailableException extends Error { }
  export class HttpException extends Error {
    constructor(message: string, status: number);
    getStatus(): number;
    getResponse(): any;
  }
  export class Logger {
    constructor(context?: string);
    log(message: string): void;
    error(message: string): void;
    warn(message: string): void;
  }
  export interface ModuleMetadata {
    imports?: any[];
    controllers?: any[];
    providers?: any[];
    exports?: any[];
  }
  export interface NestInterceptor {
    intercept(context: ExecutionContext, next: CallHandler): Observable<any>;
  }
  export interface ExecutionContext {
    switchToHttp(): any;
    switchToWs(): any;
    switchToRpc(): any;
    getClass(): any;
    getHandler(): any;
    getArgs(): any[];
    getArgByIndex(index: number): any;
  }
  export interface CallHandler {
    handle(): Observable<any>;
  }
  export interface ExceptionFilter<T = any> {
    catch(exception: T, host: ArgumentsHost): void;
  }
  export interface ArgumentsHost {
    switchToHttp(): HttpArgumentsHost;
    switchToWs(): WsArgumentsHost;
    switchToRpc(): RpcArgumentsHost;
    getArgs<T extends any[] = any[]>(): T;
    getArgByIndex<T = any>(index: number): T;
  }
  export interface HttpArgumentsHost {
    getRequest<T = any>(): T;
    getResponse<T = any>(): T;
    getNext<T = any>(): T;
  }
  export interface WsArgumentsHost {
    getClient<T = any>(): T;
    getData<T = any>(): T;
  }
  export interface RpcArgumentsHost {
    getData<T = any>(): T;
    getContext<T = any>(): T;
  }
  export function Catch(...exceptions: any[]): ClassDecorator;
  export class HttpStatus {
    static OK: number;
    static CREATED: number;
    static BAD_REQUEST: number;
    static UNAUTHORIZED: number;
    static FORBIDDEN: number;
    static NOT_FOUND: number;
    static INTERNAL_SERVER_ERROR: number;
  }
  export function HttpCode(code: number): MethodDecorator;
  export function Headers(headers: Record<string, string>): MethodDecorator;
  export function UploadedFile(fieldName?: string): ParameterDecorator;
  export interface CanActivate {
    canActivate(context: ExecutionContext): boolean | Promise<boolean> | Observable<boolean>;
  }
  export interface OnModuleInit {
    onModuleInit(): void | Promise<void>;
  }
  export interface OnModuleDestroy {
    onModuleDestroy(): void | Promise<void>;
  }
  export function Module(metadata: ModuleMetadata): ClassDecorator;
  export function Global(): ClassDecorator;
  export class Injectable { }
  export class Controller { }
}

