declare module 'rxjs' {
  export class Observable<T> {
    constructor(subscribe?: (this: Observable<T>, subscriber: any) => void);
    pipe(...operations: any[]): Observable<any>;
    subscribe(observer?: any): any;
  }
}

declare module 'rxjs/operators' {
  export function tap<T>(next?: (value: T) => void, error?: (error: any) => void, complete?: () => void): (source: Observable<T>) => Observable<T>;
  export function map<T, R>(project: (value: T, index: number) => R): (source: Observable<T>) => Observable<R>;
  export function catchError<T, R>(selector: (err: any, caught: Observable<T>) => Observable<R>): (source: Observable<T>) => Observable<R>;
  export function filter<T>(predicate: (value: T, index: number) => boolean): (source: Observable<T>) => Observable<T>;
}

